// Node class represents a node in the linked list
struct Node {
    int data;     // Data value
    Node* next;   // Pointer to next node

    // Constructor with data and next
    Node(int data1, Node* next1) {
        data = data1;
        next = next1;
    }

    // Constructor with only data
    Node(int data1) {
        data = data1;
        next = nullptr;
    }
};

int main() {
    int T, N, arr[10];
    cin >> T;
    while (T--) {
        cin >> N;
        for (int i = 0; i < N; i++) {
            cin >> arr[i];
        }
        Node* y = new Node(arr[0]);
        cout << y << '\n';
        cout << y->data << '\n';
    }
    return 0;
}

