function main() {
    const readline = require('readline').createInterface({
        input: process.stdin,
        output: process.stdout
    });
    let i = 0;
    let T;
    let N;
    let arr;
    readline.on('line', line => {
        if (i === 0) {
            T = parseInt(line);
        } else if (i % 2 === 1) {
            N = parseInt(line);
        } else {
            arr = line.split(' ').map(num => parseInt(num));
            let y = new Node(arr[0]);
            console.log(y);
            console.log(y.data);
            if (i / 2 === T) {
                process.exit();
            }
        }
        i++;
    });
}

main();

